#include <stdio.h>

void swap(int *a, int *b) {
    int tmp = *a;
    *a = *b;
    *b = tmp;
}

validation.test_code:
void test_swap_basic(void) {
    int x = 5, y = 17;
    swap(&x, &y);
    TEST_ASSERT_EQUAL_INT(17, x);
    TEST_ASSERT_EQUAL_INT(5, y);
}

void test_swap_same_value(void) {
    int x = 42, y = 42;
    swap(&x, &y);
    TEST_ASSERT_EQUAL_INT(42, x);
    TEST_ASSERT_EQUAL_INT(42, y);
}

void test_swap_negative(void) {
    int x = -10, y = 20;
    swap(&x, &y);
    TEST_ASSERT_EQUAL_INT(20, x);
    TEST_ASSERT_EQUAL_INT(-10, y);
}

void test_swap_zero(void) {
    int x = 0, y = 100;
    swap(&x, &y);
    TEST_ASSERT_EQUAL_INT(100, x);
    TEST_ASSERT_EQUAL_INT(0, y);
}

int main(void) {
    RUN_TEST(test_swap_basic);
    RUN_TEST(test_swap_same_value);
    RUN_TEST(test_swap_negative);
    RUN_TEST(test_swap_zero);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

